INSERT INTO ai_exam_analysis (
    register_id, check_request_id, inspection_request_id, analysis_type, original_result, abnormal_indicators,
    risk_level, analysis_report, correlation_analysis, model_id
) VALUES (
    #{registerId}, #{checkRequestId}, #{inspectionRequestId}, #{analysisType}, #{originalResult}, #{abnormalIndicators},
    #{riskLevel}, #{analysisReport}, #{correlationAnalysis}, #{modelId}
)

INSERT INTO ai_diagnosis_suggestion (
    register_id, disease_id, disease_name, recommend_icd, probability,
    risk_level, treatment_direction, diagnosis_basis, sort_order, model_id
) VALUES (
    #{registerId}, #{diseaseId}, #{diseaseName}, #{recommendIcd}, #{probability},
    #{riskLevel}, #{treatmentDirection}, #{diagnosisBasis}, #{sortOrder}, #{modelId}
)

INSERT INTO ai_drug_suggestion (
    register_id, drug_id, drug_name, recommend_usage, recommend_quantity,
    confidence, recommendation_basis, caution_notes, sort_order, model_id
) VALUES (
    #{registerId}, #{drugId}, #{drugName}, #{recommendUsage}, #{recommendQuantity},
    #{confidence}, #{recommendationBasis}, #{cautionNotes}, #{sortOrder}, #{modelId}
)

